import os
import sqlite3
import urllib.parse
from flask import Flask, render_template, request, session, redirect, url_for, g

app = Flask(__name__)
app.secret_key = os.urandom(32)
DATABASE = '/tmp/aetheris_dynamics.db'

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DATABASE)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def waf_filter(payload):
    # Layer 1: Block obvious SQL keywords (Case Insensitive)
    forbidden = ['SELECT', 'UNION', 'WHERE', 'AND', 'OR', 'INSERT', 'DELETE', 'UPDATE', 'DROP', ' ', '--', '/*']
    decoded_payload = urllib.parse.unquote(payload).upper()
    for word in forbidden:
        if word in decoded_payload:
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user'] = user['username']
            session['role'] = user['role']
            return redirect(url_for('dashboard'))
        return "Invalid credentials", 401
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session: return redirect(url_for('login'))
    db = get_db()
    assets = db.execute('SELECT * FROM assets LIMIT 5').fetchall()
    return render_template('dashboard.html', assets=assets)

@app.route('/robots.txt')
def robots():
    return "User-agent: *\nDisallow: /console/diagnostics\n"

@app.route('/console/diagnostics')
def diagnostics():
    if 'user' not in session: return redirect(url_for('login'))

    sync_id = request.args.get('sync_id', '')
    status_message = ""

    if sync_id:
        # SECURITY LAYER: WAF Check (Vulnerable to Double Decoding)
        if not waf_filter(sync_id):
            return "Security Alert: Malicious activity detected.", 403

        # LAYER 2: Double decoding logic flaw
        # The application decodes the parameter AGAIN before use
        final_sync_id = urllib.parse.unquote(sync_id)

        try:
            db = get_db()
            # Intentional SQLi in legacy diagnostics module
            query = f"SELECT id FROM sync_logs WHERE sync_id = '{final_sync_id}'"
            result = db.execute(query).fetchone()

            if result:
                status_message = f"Sync Log Found: Asset Hash {os.urandom(8).hex()}"
            else:
                status_message = "No Log Found for provided Sync ID."
        except Exception as e:
            # Hide actual error, but indicate failure
            status_message = "Diagnostic Engine Error."

    return render_template('diagnostics.html', status=status_message)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

